import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {

    // Function to check if a given 'm' is valid
    public static boolean isValid(long m, long[][] A, long N, long M) {
        long last = A[0][0];
        for (long i = 1; i < N; i++) {
            last = Math.max(last + m, A[(int)i][0]);
            if (last > A[(int)i][1]) {
                return false;
            }
        }

        long first = last;

        for (long i = N - 2; i >= 0; i--) {
            first = Math.min(first - m, A[(int)i][1]);
            if (first < A[(int)i][0]) {
                return false;
            }
        }

        return first + M - last >= m;
    }

    // Function to find the clean value around k
    public static long findCleanValue(long k, long[][] A, long N, long M) {
        for (long m = k + 1; m >= k - 1; m--) {
            if (m > 0 && isValid(m, A, N, M)) {
                return m;
            }
        }
        return k;
    }

    public static void main(String[] args) throws java.lang.Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        long l = 0;
        long h = (long) Math.pow(10, 18);

        String[] input = br.readLine().split(" ");
        long M = Long.parseLong(input[0]);
        long N = Long.parseLong(input[1]);

        long[][] A = new long[(int)N][2];
        for (int i = 0; i < N; i++) {
            input = br.readLine().split(" ");
            A[i][0] = Long.parseLong(input[0]);
            A[i][1] = Long.parseLong(input[1]);
        }

        Arrays.sort(A, Comparator.comparingLong(o -> o[0]));

        while (l < h) {
            long m = (l + h) >> 1;

            if (isValid(m, A, N, M)) {
                l = m + 1;
            } else {
                h = m - 1;
            }
        }

        System.out.println(findCleanValue(l, A, N, M));
    }
}
